import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { QUERY_KEYS } from '../constants'
import { createTodo, getTodos, toggleTodo } from '../api/todos'
import type { Todo } from '../types'

export function useTodos() {
  const { data: todos = [], isLoading, isError } = useQuery({
    queryKey: QUERY_KEYS.TODOS,
    queryFn: getTodos,
  })
  return { todos, isLoading, isError }
}

export function useCreateTodo() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: createTodo,
    onMutate: async (text) => {
      await queryClient.cancelQueries({ queryKey: QUERY_KEYS.TODOS })
      const previous = queryClient.getQueryData<Todo[]>(QUERY_KEYS.TODOS)

      const optimisticTodo: Todo = {
        id: -Date.now(),
        text,
        completed: false,
        createdAt: new Date().toISOString(),
      }

      queryClient.setQueryData<Todo[]>(QUERY_KEYS.TODOS, (old) => [
        ...(old ?? []),
        optimisticTodo,
      ])

      return { previous }
    },
    onError: (_err, _text, context) => {
      if (context?.previous) {
        queryClient.setQueryData(QUERY_KEYS.TODOS, context.previous)
      }
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.TODOS })
    },
  })
}

export function useToggleTodo() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: ({ id, completed }: { id: number; completed: boolean }) =>
      toggleTodo(id, completed),
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: QUERY_KEYS.TODOS })
    },
  })
}

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, fireEvent } from '@testing-library/react'
import { TodoItem } from '../../components/TodoItem'
import type { Todo } from '../../types'

const activeTodo: Todo = {
  id: 1,
  text: 'Buy groceries',
  completed: false,
  createdAt: '2026-03-06T10:00:00.000Z',
}

const completedTodo: Todo = {
  id: 2,
  text: 'Walk the dog',
  completed: true,
  createdAt: '2026-03-06T11:00:00.000Z',
}

const mockOnToggle = vi.fn()

describe('TodoItem', () => {
  beforeEach(() => {
    mockOnToggle.mockReset()
  })

  it('renders active todo text in primary color without strikethrough', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} />)
    const text = screen.getByText('Buy groceries')
    expect(text).toBeInTheDocument()
    expect(text).toHaveClass('text-text-primary')
    expect(text).not.toHaveClass('line-through')
    expect(text).not.toHaveClass('italic')
  })

  it('renders completed todo with strikethrough and italic in secondary color', () => {
    render(<TodoItem todo={completedTodo} onToggle={mockOnToggle} />)
    const text = screen.getByText('Walk the dog')
    expect(text).toHaveClass('text-text-secondary')
    expect(text).toHaveClass('line-through')
    expect(text).toHaveClass('italic')
  })

  it('displays creation timestamp as uppercase metadata', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} />)
    const timestamp = screen.getByText('Mar 6, 2026')
    expect(timestamp).toBeInTheDocument()
    expect(timestamp).toHaveClass('uppercase')
  })

  it('has role="checkbox" and aria-checked matching completion state', () => {
    const { rerender } = render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} />)
    const activeItem = screen.getByRole('checkbox')
    expect(activeItem).toHaveAttribute('aria-checked', 'false')

    rerender(<TodoItem todo={completedTodo} onToggle={mockOnToggle} />)
    const completedItem = screen.getByRole('checkbox')
    expect(completedItem).toHaveAttribute('aria-checked', 'true')
  })

  it('calls onToggle with (id, true) when clicking an active todo', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} />)
    fireEvent.click(screen.getByRole('checkbox'))
    expect(mockOnToggle).toHaveBeenCalledWith(1, true)
    expect(mockOnToggle).toHaveBeenCalledTimes(1)
  })

  it('calls onToggle with (id, false) when clicking a completed todo', () => {
    render(<TodoItem todo={completedTodo} onToggle={mockOnToggle} />)
    fireEvent.click(screen.getByRole('checkbox'))
    expect(mockOnToggle).toHaveBeenCalledWith(2, false)
    expect(mockOnToggle).toHaveBeenCalledTimes(1)
  })

  it('has cursor-pointer and select-none classes for click affordance', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} />)
    const item = screen.getByRole('checkbox')
    expect(item).toHaveClass('cursor-pointer')
    expect(item).toHaveClass('select-none')
  })

  it('has tabIndex={0} for keyboard accessibility', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} />)
    const item = screen.getByRole('checkbox')
    expect(item).toHaveAttribute('tabindex', '0')
  })

  it('does not call onToggle when not clicked', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} />)
    expect(mockOnToggle).not.toHaveBeenCalled()
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, fireEvent } from '@testing-library/react'
import { TodoList } from '../../components/TodoList'

const mockUseTodos = vi.fn()
const mockMutate = vi.fn()

vi.mock('../../hooks/useTodos', () => ({
  useTodos: () => mockUseTodos(),
  useToggleTodo: () => ({ mutate: mockMutate }),
}))

const mockTodos = [
  { id: 1, text: 'First task', completed: false, createdAt: '2026-03-06T10:00:00Z' },
  { id: 2, text: 'Second task', completed: true, createdAt: '2026-03-06T11:00:00Z' },
]

describe('TodoList', () => {
  beforeEach(() => {
    mockUseTodos.mockReset()
    mockMutate.mockReset()
  })

  it('renders all todos in a list', () => {
    mockUseTodos.mockReturnValue({ todos: mockTodos, isLoading: false, isError: false })
    render(<TodoList />)
    expect(screen.getByText('First task')).toBeInTheDocument()
    expect(screen.getByText('Second task')).toBeInTheDocument()
  })

  it('renders todos in order (first created first in DOM)', () => {
    mockUseTodos.mockReturnValue({ todos: mockTodos, isLoading: false, isError: false })
    render(<TodoList />)
    const items = screen.getAllByRole('checkbox')
    expect(items).toHaveLength(2)
    expect(items[0]).toHaveTextContent('First task')
    expect(items[1]).toHaveTextContent('Second task')
  })

  it('has role="list" and aria-label="Task list"', () => {
    mockUseTodos.mockReturnValue({ todos: mockTodos, isLoading: false, isError: false })
    render(<TodoList />)
    const list = screen.getByRole('list', { name: 'Task list' })
    expect(list).toBeInTheDocument()
  })

  it('renders nothing when loading', () => {
    mockUseTodos.mockReturnValue({ todos: [], isLoading: true, isError: false })
    const { container } = render(<TodoList />)
    expect(container.innerHTML).toBe('')
  })

  it('renders nothing on error', () => {
    mockUseTodos.mockReturnValue({ todos: [], isLoading: false, isError: true })
    const { container } = render(<TodoList />)
    expect(container.innerHTML).toBe('')
  })

  it('renders nothing when todos array is empty', () => {
    mockUseTodos.mockReturnValue({ todos: [], isLoading: false, isError: false })
    const { container } = render(<TodoList />)
    expect(container.innerHTML).toBe('')
  })

  it('calls toggle mutation when a todo is clicked', () => {
    mockUseTodos.mockReturnValue({ todos: mockTodos, isLoading: false, isError: false })
    render(<TodoList />)
    const items = screen.getAllByRole('checkbox')

    fireEvent.click(items[0])
    expect(mockMutate).toHaveBeenCalledWith({ id: 1, completed: true })

    mockMutate.mockClear()
    fireEvent.click(items[1])
    expect(mockMutate).toHaveBeenCalledWith({ id: 2, completed: false })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { createTodo, getTodos, toggleTodo } from '../../api/todos'

const mockFetch = vi.fn()
vi.stubGlobal('fetch', mockFetch)

describe('createTodo API', () => {
  beforeEach(() => {
    mockFetch.mockReset()
  })

  it('sends POST /api/todos with JSON body and returns created todo', async () => {
    const mockTodo = { id: 1, text: 'Buy groceries', completed: false, createdAt: '2026-03-07' }
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockTodo),
    })

    const result = await createTodo('Buy groceries')

    expect(mockFetch).toHaveBeenCalledWith('/api/todos', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text: 'Buy groceries' }),
    })
    expect(result).toEqual(mockTodo)
  })

  it('throws with server error message on non-ok response', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 400,
      json: () => Promise.resolve({ statusCode: 400, error: 'Bad Request', message: 'Todo description cannot be empty' }),
    })

    await expect(createTodo('')).rejects.toThrow('Todo description cannot be empty')
  })

  it('throws generic message when server response is not JSON', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 500,
      json: () => Promise.reject(new Error('not json')),
    })

    await expect(createTodo('test')).rejects.toThrow('Failed to create todo')
  })
})

describe('toggleTodo API', () => {
  beforeEach(() => {
    mockFetch.mockReset()
  })

  it('sends PATCH /api/todos/:id with completed: true and returns updated todo', async () => {
    const mockTodo = { id: 1, text: 'Buy groceries', completed: true, createdAt: '2026-03-07' }
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockTodo),
    })

    const result = await toggleTodo(1, true)

    expect(mockFetch).toHaveBeenCalledWith('/api/todos/1', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ completed: true }),
    })
    expect(result).toEqual(mockTodo)
  })

  it('sends PATCH /api/todos/:id with completed: false for uncomplete', async () => {
    const mockTodo = { id: 2, text: 'Walk the dog', completed: false, createdAt: '2026-03-07' }
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockTodo),
    })

    const result = await toggleTodo(2, false)

    expect(mockFetch).toHaveBeenCalledWith('/api/todos/2', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ completed: false }),
    })
    expect(result).toEqual(mockTodo)
  })

  it('throws with server error message on non-ok response', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 404,
      json: () => Promise.resolve({ statusCode: 404, error: 'Not Found', message: 'Todo not found' }),
    })

    await expect(toggleTodo(999, true)).rejects.toThrow('Todo not found')
  })

  it('throws generic message when server response is not JSON', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 500,
      json: () => Promise.reject(new Error('not json')),
    })

    await expect(toggleTodo(1, true)).rejects.toThrow('Failed to update todo')
  })
})

describe('getTodos API', () => {
  beforeEach(() => {
    mockFetch.mockReset()
  })

  it('sends GET /api/todos and returns todo array', async () => {
    const mockTodos = [
      { id: 1, text: 'First', completed: false, createdAt: '2026-03-07' },
      { id: 2, text: 'Second', completed: true, createdAt: '2026-03-07' },
    ]
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockTodos),
    })

    const result = await getTodos()

    expect(mockFetch).toHaveBeenCalledWith('/api/todos')
    expect(result).toEqual(mockTodos)
  })

  it('throws on non-ok response', async () => {
    mockFetch.mockResolvedValueOnce({ ok: false, status: 500 })

    await expect(getTodos()).rejects.toThrow('Failed to fetch todos')
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { renderHook, act, waitFor } from '@testing-library/react'
import { QueryClient, QueryClientProvider } from '@tanstack/react-query'
import type { ReactNode } from 'react'
import { useCreateTodo, useTodos, useToggleTodo } from '../../hooks/useTodos'

const mockCreateTodo = vi.fn()
const mockGetTodos = vi.fn()
const mockToggleTodo = vi.fn()
vi.mock('../../api/todos', () => ({
  createTodo: (...args: unknown[]) => mockCreateTodo(...args),
  getTodos: () => mockGetTodos(),
  toggleTodo: (...args: unknown[]) => mockToggleTodo(...args),
}))

function createWrapper() {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false }, mutations: { retry: false } },
  })
  return function Wrapper({ children }: { children: ReactNode }) {
    return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
  }
}

describe('useTodos', () => {
  beforeEach(() => {
    mockGetTodos.mockReset()
  })

  it('returns todos from API', async () => {
    const mockTodos = [
      { id: 1, text: 'First', completed: false, createdAt: '2026-03-07' },
      { id: 2, text: 'Second', completed: true, createdAt: '2026-03-07' },
    ]
    mockGetTodos.mockResolvedValueOnce(mockTodos)

    const { result } = renderHook(() => useTodos(), { wrapper: createWrapper() })

    await waitFor(() => {
      expect(result.current.todos).toEqual(mockTodos)
    })
    expect(result.current.isLoading).toBe(false)
    expect(result.current.isError).toBe(false)
  })

  it('defaults to empty array when no data', async () => {
    mockGetTodos.mockResolvedValueOnce([])

    const { result } = renderHook(() => useTodos(), { wrapper: createWrapper() })

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })
    expect(result.current.todos).toEqual([])
  })

  it('sets isError on fetch failure', async () => {
    mockGetTodos.mockRejectedValueOnce(new Error('Network error'))

    const { result } = renderHook(() => useTodos(), { wrapper: createWrapper() })

    await waitFor(() => {
      expect(result.current.isError).toBe(true)
    })
  })
})

describe('useCreateTodo', () => {
