import type { Todo } from '../types'

interface TodoItemProps {
  todo: Todo
  onToggle: (id: number, completed: boolean) => void
  onDelete: (id: number) => void
}

export function TodoItem({ todo, onToggle, onDelete }: TodoItemProps) {
  const formattedDate = new Date(todo.createdAt).toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  })

  const handleClick = () => {
    onToggle(todo.id, !todo.completed)
  }

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation()
    onDelete(todo.id)
  }

  return (
    <li
      role="checkbox"
      aria-checked={todo.completed}
      tabIndex={0}
      onClick={handleClick}
      className="group relative flex flex-col pl-5 pr-14 py-4 border-l-2 border-transparent hover:border-border hover:bg-surface-hover transition-all duration-300 motion-reduce:transition-none cursor-pointer select-none"
    >
      <span
        className={`text-[1.125rem] font-light transition-all duration-300 motion-reduce:transition-none ${
          todo.completed
            ? 'text-text-secondary line-through italic'
            : 'text-text-primary'
        }`}
      >
        {todo.text}
      </span>
      <span className="text-[0.6875rem] font-normal uppercase tracking-[0.05em] text-text-placeholder mt-1">
        {formattedDate}
      </span>
      <button
        type="button"
        aria-label={`Delete task: ${todo.text}`}
        onClick={handleDelete}
        className="absolute right-2 top-1/2 -translate-y-1/2 w-11 h-11 flex items-center justify-center text-text-secondary text-lg opacity-100 lg:opacity-0 lg:group-hover:opacity-100 transition-opacity duration-200 motion-reduce:transition-none"
      >
        ×
      </button>
    </li>
  )
}

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { createTodo, deleteTodo, getTodos, toggleTodo } from '../../api/todos'

const mockFetch = vi.fn()
vi.stubGlobal('fetch', mockFetch)

describe('createTodo API', () => {
  beforeEach(() => {
    mockFetch.mockReset()
  })

  it('sends POST /api/todos with JSON body and returns created todo', async () => {
    const mockTodo = { id: 1, text: 'Buy groceries', completed: false, createdAt: '2026-03-07' }
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockTodo),
    })

    const result = await createTodo('Buy groceries')

    expect(mockFetch).toHaveBeenCalledWith('/api/todos', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text: 'Buy groceries' }),
    })
    expect(result).toEqual(mockTodo)
  })

  it('throws with server error message on non-ok response', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 400,
      json: () => Promise.resolve({ statusCode: 400, error: 'Bad Request', message: 'Todo description cannot be empty' }),
    })

    await expect(createTodo('')).rejects.toThrow('Todo description cannot be empty')
  })

  it('throws generic message when server response is not JSON', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 500,
      json: () => Promise.reject(new Error('not json')),
    })

    await expect(createTodo('test')).rejects.toThrow('Failed to create todo')
  })
})

describe('toggleTodo API', () => {
  beforeEach(() => {
    mockFetch.mockReset()
  })

  it('sends PATCH /api/todos/:id with completed: true and returns updated todo', async () => {
    const mockTodo = { id: 1, text: 'Buy groceries', completed: true, createdAt: '2026-03-07' }
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockTodo),
    })

    const result = await toggleTodo(1, true)

    expect(mockFetch).toHaveBeenCalledWith('/api/todos/1', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ completed: true }),
    })
    expect(result).toEqual(mockTodo)
  })

  it('sends PATCH /api/todos/:id with completed: false for uncomplete', async () => {
    const mockTodo = { id: 2, text: 'Walk the dog', completed: false, createdAt: '2026-03-07' }
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockTodo),
    })

    const result = await toggleTodo(2, false)

    expect(mockFetch).toHaveBeenCalledWith('/api/todos/2', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ completed: false }),
    })
    expect(result).toEqual(mockTodo)
  })

  it('throws with server error message on non-ok response', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 404,
      json: () => Promise.resolve({ statusCode: 404, error: 'Not Found', message: 'Todo not found' }),
    })

    await expect(toggleTodo(999, true)).rejects.toThrow('Todo not found')
  })

  it('throws generic message when server response is not JSON', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 500,
      json: () => Promise.reject(new Error('not json')),
    })

    await expect(toggleTodo(1, true)).rejects.toThrow('Failed to update todo')
  })
})

describe('deleteTodo API', () => {
  beforeEach(() => {
    mockFetch.mockReset()
  })

  it('sends DELETE /api/todos/:id with no body and returns void on 204', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: true,
      status: 204,
    })

    await deleteTodo(1)

    expect(mockFetch).toHaveBeenCalledWith('/api/todos/1', {
      method: 'DELETE',
    })
  })

  it('throws with server error message on 404', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 404,
      json: () => Promise.resolve({ statusCode: 404, error: 'Not Found', message: 'Todo not found' }),
    })

    await expect(deleteTodo(999)).rejects.toThrow('Todo not found')
  })

  it('throws generic message when server error response is not JSON', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 500,
      json: () => Promise.reject(new Error('not json')),
    })

    await expect(deleteTodo(1)).rejects.toThrow('Failed to delete todo')
  })
})

describe('getTodos API', () => {
  beforeEach(() => {
    mockFetch.mockReset()
  })

  it('sends GET /api/todos and returns todo array', async () => {
    const mockTodos = [
      { id: 1, text: 'First', completed: false, createdAt: '2026-03-07' },
      { id: 2, text: 'Second', completed: true, createdAt: '2026-03-07' },
    ]
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockTodos),
    })

    const result = await getTodos()

    expect(mockFetch).toHaveBeenCalledWith('/api/todos')
    expect(result).toEqual(mockTodos)
  })

  it('throws on non-ok response', async () => {
    mockFetch.mockResolvedValueOnce({ ok: false, status: 500 })

    await expect(getTodos()).rejects.toThrow('Failed to fetch todos')
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { renderHook, act, waitFor } from '@testing-library/react'
import { QueryClient, QueryClientProvider } from '@tanstack/react-query'
import type { ReactNode } from 'react'
import { useCreateTodo, useDeleteTodo, useTodos, useToggleTodo } from '../../hooks/useTodos'

const mockCreateTodo = vi.fn()
const mockDeleteTodo = vi.fn()
const mockGetTodos = vi.fn()
const mockToggleTodo = vi.fn()
vi.mock('../../api/todos', () => ({
  createTodo: (...args: unknown[]) => mockCreateTodo(...args),
  deleteTodo: (...args: unknown[]) => mockDeleteTodo(...args),
  getTodos: () => mockGetTodos(),
  toggleTodo: (...args: unknown[]) => mockToggleTodo(...args),
}))

function createWrapper() {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false }, mutations: { retry: false } },
  })
  return function Wrapper({ children }: { children: ReactNode }) {
    return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
  }
}

describe('useTodos', () => {
  beforeEach(() => {
    mockGetTodos.mockReset()
  })

  it('returns todos from API', async () => {
    const mockTodos = [
      { id: 1, text: 'First', completed: false, createdAt: '2026-03-07' },
      { id: 2, text: 'Second', completed: true, createdAt: '2026-03-07' },
    ]
    mockGetTodos.mockResolvedValueOnce(mockTodos)

    const { result } = renderHook(() => useTodos(), { wrapper: createWrapper() })

    await waitFor(() => {
      expect(result.current.todos).toEqual(mockTodos)
    })
    expect(result.current.isLoading).toBe(false)
    expect(result.current.isError).toBe(false)
  })

  it('defaults to empty array when no data', async () => {
    mockGetTodos.mockResolvedValueOnce([])

    const { result } = renderHook(() => useTodos(), { wrapper: createWrapper() })

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false)
    })
    expect(result.current.todos).toEqual([])
  })

  it('sets isError on fetch failure', async () => {
    mockGetTodos.mockRejectedValueOnce(new Error('Network error'))

    const { result } = renderHook(() => useTodos(), { wrapper: createWrapper() })

    await waitFor(() => {
      expect(result.current.isError).toBe(true)
    })
  })
})

describe('useCreateTodo', () => {
  beforeEach(() => {
    mockCreateTodo.mockReset()
  })

  it('calls createTodo API with text', async () => {
    const mockTodo = { id: 1, text: 'Test', completed: false, createdAt: '2026-03-07' }
    mockCreateTodo.mockResolvedValueOnce(mockTodo)

    const { result } = renderHook(() => useCreateTodo(), { wrapper: createWrapper() })

    act(() => {
      result.current.mutate('Test')
    })

    await waitFor(() => {
      expect(mockCreateTodo).toHaveBeenCalledWith('Test', expect.anything())
    })
  })

  it('adds optimistic todo to cache while mutation is in-flight', async () => {
    let resolveMutation!: (value: unknown) => void
    mockCreateTodo.mockReturnValueOnce(
      new Promise((resolve) => { resolveMutation = resolve }),
    )

    const queryClient = new QueryClient({
      defaultOptions: { queries: { retry: false }, mutations: { retry: false } },
    })
    queryClient.setQueryData(['todos'], [])

    function Wrapper({ children }: { children: ReactNode }) {
      return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    }

    const { result } = renderHook(() => useCreateTodo(), { wrapper: Wrapper })

    await act(async () => {
      result.current.mutate('Optimistic test')
      // Allow microtasks (onMutate) to flush
      await new Promise((r) => setTimeout(r, 0))
    })

    // Cache should contain optimistic todo BEFORE mutation resolves
    const cached = queryClient.getQueryData<Array<{ text: string }>>(['todos'])
    expect(cached).toHaveLength(1)
    expect(cached![0].text).toBe('Optimistic test')

    // Clean up: resolve the pending mutation
    await act(async () => {
      resolveMutation({ id: 1, text: 'Optimistic test', completed: false, createdAt: '2026-03-07' })
    })
  })

  it('rolls back cache on mutation error', async () => {
    mockCreateTodo.mockRejectedValueOnce(new Error('Network error'))

    const queryClient = new QueryClient({
      defaultOptions: { queries: { retry: false }, mutations: { retry: false } },
    })
    const originalTodos = [{ id: 1, text: 'Existing', completed: false, createdAt: '2026-03-07' }]
    queryClient.setQueryData(['todos'], originalTodos)

    function Wrapper({ children }: { children: ReactNode }) {
      return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    }

    const { result } = renderHook(() => useCreateTodo(), { wrapper: Wrapper })

    act(() => {
      result.current.mutate('Will fail')
    })

    await waitFor(() => {
      expect(result.current.isError).toBe(true)
    })

    // After error, cache should be rolled back to original
    await waitFor(() => {
      const cached = queryClient.getQueryData<unknown[]>(['todos'])
      expect(cached).toEqual(originalTodos)
    })
  })
})

describe('useToggleTodo', () => {
  beforeEach(() => {
    mockToggleTodo.mockReset()
  })

  it('calls toggleTodo API with id and completed', async () => {
    const mockTodo = { id: 1, text: 'Test', completed: true, createdAt: '2026-03-07' }
    mockToggleTodo.mockResolvedValueOnce(mockTodo)

    const { result } = renderHook(() => useToggleTodo(), { wrapper: createWrapper() })

    act(() => {
      result.current.mutate({ id: 1, completed: true })
    })

    await waitFor(() => {
      expect(mockToggleTodo).toHaveBeenCalledWith(1, true)
    })
  })

  it('invalidates todos query on settled after success', async () => {
    const mockTodo = { id: 1, text: 'Test', completed: true, createdAt: '2026-03-07' }
    mockToggleTodo.mockResolvedValueOnce(mockTodo)
    mockGetTodos.mockResolvedValue([mockTodo])

    const queryClient = new QueryClient({
      defaultOptions: { queries: { retry: false }, mutations: { retry: false } },
    })
    queryClient.setQueryData(['todos'], [{ id: 1, text: 'Test', completed: false, createdAt: '2026-03-07' }])

    function Wrapper({ children }: { children: ReactNode }) {
      return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    }

    const { result } = renderHook(() => useToggleTodo(), { wrapper: Wrapper })

    act(() => {
      result.current.mutate({ id: 1, completed: true })
    })

    await waitFor(() => {
      expect(result.current.isSuccess).toBe(true)
    })

    // After settled, the query should be invalidated (triggers refetch)
    await waitFor(() => {
      const state = queryClient.getQueryState(['todos'])
      expect(state?.isInvalidated).toBe(true)
    })
  })

  it('invalidates todos query on settled after error', async () => {
    mockToggleTodo.mockRejectedValueOnce(new Error('Network error'))
    mockGetTodos.mockResolvedValue([])

    const queryClient = new QueryClient({
      defaultOptions: { queries: { retry: false }, mutations: { retry: false } },
    })
    queryClient.setQueryData(['todos'], [{ id: 1, text: 'Test', completed: false, createdAt: '2026-03-07' }])

    function Wrapper({ children }: { children: ReactNode }) {
      return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    }

    const { result } = renderHook(() => useToggleTodo(), { wrapper: Wrapper })

    act(() => {
      result.current.mutate({ id: 1, completed: true })
    })

    await waitFor(() => {
      expect(result.current.isError).toBe(true)
    })

    // After settled (even on error), the query should be invalidated
    await waitFor(() => {
      const state = queryClient.getQueryState(['todos'])
      expect(state?.isInvalidated).toBe(true)
    })
  })
})

describe('useDeleteTodo', () => {
  beforeEach(() => {
    mockDeleteTodo.mockReset()
  })

  it('calls deleteTodo API with id', async () => {
    mockDeleteTodo.mockResolvedValueOnce(undefined)

    const { result } = renderHook(() => useDeleteTodo(), { wrapper: createWrapper() })

    act(() => {
      result.current.mutate(1)
    })

    await waitFor(() => {
      expect(mockDeleteTodo).toHaveBeenCalledWith(1)
    })
  })

  it('invalidates todos query on settled after success', async () => {
    mockDeleteTodo.mockResolvedValueOnce(undefined)
    mockGetTodos.mockResolvedValue([])

    const queryClient = new QueryClient({
      defaultOptions: { queries: { retry: false }, mutations: { retry: false } },
    })
    queryClient.setQueryData(['todos'], [{ id: 1, text: 'Test', completed: false, createdAt: '2026-03-07' }])

    function Wrapper({ children }: { children: ReactNode }) {
      return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    }

    const { result } = renderHook(() => useDeleteTodo(), { wrapper: Wrapper })

    act(() => {
      result.current.mutate(1)
    })

    await waitFor(() => {
      expect(result.current.isSuccess).toBe(true)
    })

    await waitFor(() => {
      const state = queryClient.getQueryState(['todos'])
      expect(state?.isInvalidated).toBe(true)
    })
  })

  it('invalidates todos query on settled after error', async () => {
    mockDeleteTodo.mockRejectedValueOnce(new Error('Network error'))
    mockGetTodos.mockResolvedValue([])

    const queryClient = new QueryClient({
      defaultOptions: { queries: { retry: false }, mutations: { retry: false } },
    })
    queryClient.setQueryData(['todos'], [{ id: 1, text: 'Test', completed: false, createdAt: '2026-03-07' }])

    function Wrapper({ children }: { children: ReactNode }) {
      return <QueryClientProvider client={queryClient}>{children}</QueryClientProvider>
    }

    const { result } = renderHook(() => useDeleteTodo(), { wrapper: Wrapper })

    act(() => {
      result.current.mutate(1)
    })

    await waitFor(() => {
      expect(result.current.isError).toBe(true)
    })

    await waitFor(() => {
      const state = queryClient.getQueryState(['todos'])
      expect(state?.isInvalidated).toBe(true)
    })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, fireEvent } from '@testing-library/react'
import { TodoItem } from '../../components/TodoItem'
import type { Todo } from '../../types'

const activeTodo: Todo = {
  id: 1,
  text: 'Buy groceries',
  completed: false,
  createdAt: '2026-03-06T10:00:00.000Z',
}

const completedTodo: Todo = {
  id: 2,
  text: 'Walk the dog',
  completed: true,
  createdAt: '2026-03-06T11:00:00.000Z',
}

const mockOnToggle = vi.fn()
const mockOnDelete = vi.fn()

describe('TodoItem', () => {
  beforeEach(() => {
    mockOnToggle.mockReset()
    mockOnDelete.mockReset()
  })

  it('renders active todo text in primary color without strikethrough', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    const text = screen.getByText('Buy groceries')
    expect(text).toBeInTheDocument()
    expect(text).toHaveClass('text-text-primary')
    expect(text).not.toHaveClass('line-through')
    expect(text).not.toHaveClass('italic')
  })

  it('renders completed todo with strikethrough and italic in secondary color', () => {
    render(<TodoItem todo={completedTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    const text = screen.getByText('Walk the dog')
    expect(text).toHaveClass('text-text-secondary')
    expect(text).toHaveClass('line-through')
    expect(text).toHaveClass('italic')
  })

  it('displays creation timestamp as uppercase metadata', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    const timestamp = screen.getByText('Mar 6, 2026')
    expect(timestamp).toBeInTheDocument()
    expect(timestamp).toHaveClass('uppercase')
  })

  it('has role="checkbox" and aria-checked matching completion state', () => {
    const { rerender } = render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    const activeItem = screen.getByRole('checkbox')
    expect(activeItem).toHaveAttribute('aria-checked', 'false')

    rerender(<TodoItem todo={completedTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    const completedItem = screen.getByRole('checkbox')
    expect(completedItem).toHaveAttribute('aria-checked', 'true')
  })

  it('calls onToggle with (id, true) when clicking an active todo', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    fireEvent.click(screen.getByRole('checkbox'))
    expect(mockOnToggle).toHaveBeenCalledWith(1, true)
    expect(mockOnToggle).toHaveBeenCalledTimes(1)
  })

  it('calls onToggle with (id, false) when clicking a completed todo', () => {
    render(<TodoItem todo={completedTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    fireEvent.click(screen.getByRole('checkbox'))
    expect(mockOnToggle).toHaveBeenCalledWith(2, false)
    expect(mockOnToggle).toHaveBeenCalledTimes(1)
  })

  it('has cursor-pointer and select-none classes for click affordance', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    const item = screen.getByRole('checkbox')
    expect(item).toHaveClass('cursor-pointer')
    expect(item).toHaveClass('select-none')
  })

  it('has tabIndex={0} for keyboard accessibility', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    const item = screen.getByRole('checkbox')
    expect(item).toHaveAttribute('tabindex', '0')
  })

  it('does not call onToggle when not clicked', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    expect(mockOnToggle).not.toHaveBeenCalled()
  })

  it('renders × delete button with correct aria-label', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    const deleteButton = screen.getByLabelText('Delete task: Buy groceries')
    expect(deleteButton).toBeInTheDocument()
    expect(deleteButton.textContent).toBe('×')
  })

  it('calls onDelete with todo id when × button is clicked', () => {
    render(<TodoItem todo={activeTodo} onToggle={mockOnToggle} onDelete={mockOnDelete} />)
    const deleteButton = screen.getByLabelText('Delete task: Buy groceries')
    fireEvent.click(deleteButton)
    expect(mockOnDelete).toHaveBeenCalledWith(1)
